    const { title } = req.body;
    const article = await Article.create({ title });
    res.status(201).json({
      id: article.id,
      title: article.title,
      slug: article.slug,
    });
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

app.post("/articles/bulk", async (req, res) => {
  try {
    const payload = Array.isArray(req.body) ? req.body : [];
