      individualHooks: true,
      returning: true,
    });
    res.status(201).json(
      articles.map((article) => ({
        id: article.id,
        title: article.title,
        slug: article.slug,
      }))
    );
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

